#!/usr/bin/env node

const sqlite3 = require('better-sqlite3');
const path = require('path');
const bcrypt = require('bcryptjs');

const dbPath = path.join(__dirname, 'dev.db');
console.log(`️  Creating SQLite database at: ${dbPath}`);

const db = new sqlite3(dbPath);

// Enable foreign keys
db.pragma('foreign_keys = ON');

console.log(' Creating tables...');

// Create tables directly
db.exec(`
  CREATE TABLE IF NOT EXISTS "User" (
    "id" TEXT NOT NULL PRIMARY KEY,
    "email" TEXT NOT NULL UNIQUE,
    "emailVerified" DATETIME,
    "name" TEXT,
    "image" TEXT,
    "hashedPassword" TEXT,
    "role" TEXT NOT NULL DEFAULT 'USER',
    "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updatedAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deletedAt" DATETIME
  );

  CREATE INDEX IF NOT EXISTS "User_email_idx" ON "User"("email");
  CREATE INDEX IF NOT EXISTS "User_role_idx" ON "User"("role");
  CREATE INDEX IF NOT EXISTS "User_deletedAt_idx" ON "User"("deletedAt");

  CREATE TABLE IF NOT EXISTS "Workspace" (
    "id" TEXT NOT NULL PRIMARY KEY,
    "name" TEXT NOT NULL,
    "slug" TEXT NOT NULL UNIQUE,
    "description" TEXT,
    "logo" TEXT,
    "plan" TEXT NOT NULL DEFAULT 'FREE',
    "ownerId" TEXT NOT NULL,
    "stripeCustomerId" TEXT UNIQUE,
    "stripeSubscriptionId" TEXT UNIQUE,
    "stripePriceId" TEXT,
    "subscriptionStatus" TEXT NOT NULL DEFAULT 'ACTIVE',
    "currentPeriodEnd" DATETIME,
    "usageCount" INTEGER NOT NULL DEFAULT 0,
    "usageLimit" INTEGER NOT NULL DEFAULT 10,
    "dialectPreference" TEXT NOT NULL DEFAULT 'EGYPTIAN',
    "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updatedAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deletedAt" DATETIME,
    FOREIGN KEY ("ownerId") REFERENCES "User"("id") ON DELETE CASCADE
  );

  CREATE INDEX IF NOT EXISTS "Workspace_ownerId_idx" ON "Workspace"("ownerId");
  CREATE INDEX IF NOT EXISTS "Workspace_slug_idx" ON "Workspace"("slug");
  CREATE INDEX IF NOT EXISTS "Workspace_plan_idx" ON "Workspace"("plan");
  CREATE INDEX IF NOT EXISTS "Workspace_subscriptionStatus_idx" ON "Workspace"("subscriptionStatus");
  CREATE INDEX IF NOT EXISTS "Workspace_deletedAt_idx" ON "Workspace"("deletedAt");

  CREATE TABLE IF NOT EXISTS "WorkspaceMember" (
    "id" TEXT NOT NULL PRIMARY KEY,
    "workspaceId" TEXT NOT NULL,
    "userId" TEXT NOT NULL,
    "role" TEXT NOT NULL DEFAULT 'MEMBER',
    "invitedAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "joinedAt" DATETIME,
    "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updatedAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY ("workspaceId") REFERENCES "Workspace"("id") ON DELETE CASCADE,
    FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE,
    UNIQUE("workspaceId", "userId")
  );

  CREATE INDEX IF NOT EXISTS "WorkspaceMember_workspaceId_idx" ON "WorkspaceMember"("workspaceId");
  CREATE INDEX IF NOT EXISTS "WorkspaceMember_userId_idx" ON "WorkspaceMember"("userId");
  CREATE INDEX IF NOT EXISTS "WorkspaceMember_role_idx" ON "WorkspaceMember"("role");

  CREATE TABLE IF NOT EXISTS "Generation" (
    "id" TEXT NOT NULL PRIMARY KEY,
    "workspaceId" TEXT NOT NULL,
    "userId" TEXT NOT NULL,
    "type" TEXT NOT NULL DEFAULT 'CAPTION',
    "dialect" TEXT NOT NULL DEFAULT 'EGYPTIAN',
    "tone" TEXT NOT NULL DEFAULT 'PROFESSIONAL',
    "prompt" TEXT NOT NULL,
    "result" TEXT NOT NULL,
    "tokensUsed" INTEGER NOT NULL DEFAULT 0,
    "model" TEXT NOT NULL DEFAULT 'claude-sonnet-4-20250514',
    "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updatedAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deletedAt" DATETIME,
    FOREIGN KEY ("workspaceId") REFERENCES "Workspace"("id") ON DELETE CASCADE,
    FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE
  );

  CREATE INDEX IF NOT EXISTS "Generation_workspaceId_idx" ON "Generation"("workspaceId");
  CREATE INDEX IF NOT EXISTS "Generation_userId_idx" ON "Generation"("userId");
  CREATE INDEX IF NOT EXISTS "Generation_type_idx" ON "Generation"("type");
  CREATE INDEX IF NOT EXISTS "Generation_dialect_idx" ON "Generation"("dialect");
  CREATE INDEX IF NOT EXISTS "Generation_createdAt_idx" ON "Generation"("createdAt");
  CREATE INDEX IF NOT EXISTS "Generation_deletedAt_idx" ON "Generation"("deletedAt");
  CREATE INDEX IF NOT EXISTS "Generation_workspaceId_createdAt_idx" ON "Generation"("workspaceId", "createdAt");
`);

console.log('✅ Tables created');

// Insert demo user
console.log(' Creating demo user...');
const hashedPassword = bcrypt.hashSync('Demo@123456', 12);
const userId = Math.random().toString(36).substr(2, 9);

db.prepare(`
  INSERT INTO "User" (id, email, name, hashedPassword, emailVerified, role, createdAt, updatedAt)
  VALUES (?, ?, ?, ?, ?, ?, ?, ?)
`).run(userId, 'demo@kateb.ai', 'Demo User', hashedPassword, new Date().toISOString(), 'USER', new Date().toISOString(), new Date().toISOString());

console.log('✅ Demo user created');

// Insert workspace
console.log(' Creating workspace...');
const workspaceId = Math.random().toString(36).substr(2, 9);

db.prepare(`
  INSERT INTO "Workspace" (id, name, slug, ownerId, plan, usageLimit, dialectPreference, createdAt, updatedAt)
  VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
`).run(workspaceId, 'Demo Workspace', 'demo-workspace', userId, 'FREE', 10, 'EGYPTIAN', new Date().toISOString(), new Date().toISOString());

console.log('✅ Workspace created');

// Add user to workspace
console.log(' Adding user to workspace...');
const memberId = Math.random().toString(36).substr(2, 9);

db.prepare(`
  INSERT INTO "WorkspaceMember" (id, workspaceId, userId, role, joinedAt, createdAt, updatedAt)
  VALUES (?, ?, ?, ?, ?, ?, ?)
`).run(memberId, workspaceId, userId, 'OWNER', new Date().toISOString(), new Date().toISOString(), new Date().toISOString());

console.log('✅ User added to workspace');

db.close();

console.log('\n Database seeded successfully!\n');
console.log(' Demo Credentials:');
console.log('   Email: demo@kateb.ai');
console.log('   Password: Demo@123456\n');
console.log('️  Database location: ' + dbPath);

const { PrismaClient } = require('@prisma/client');
const bcrypt = require('bcryptjs');

const prisma = new PrismaClient();

async function main() {
  console.log(' Seeding database...');

  try {
    // Clean up existing data
    await prisma.auditLog.deleteMany();
    await prisma.approvalLink.deleteMany();
    await prisma.generationVersion.deleteMany();
    await prisma.generation.deleteMany();
    await prisma.workspaceInvite.deleteMany();
    await prisma.workspaceMember.deleteMany();
    await prisma.workspace.deleteMany();
    await prisma.verificationToken.deleteMany();
    await prisma.session.deleteMany();
    await prisma.account.deleteMany();
    await prisma.user.deleteMany();

    console.log('✅ Cleaned up existing data');

    // Create demo user
    const hashedPassword = await bcrypt.hash('Demo@123456', 12);

    const demoUser = await prisma.user.create({
      data: {
        email: 'demo@kateb.ai',
        name: 'Demo User',
        hashedPassword: hashedPassword,
        emailVerified: new Date(),
        role: 'USER',
      },
    });

    console.log('✅ Demo user created:', demoUser.email);

    // Create workspace
    const workspace = await prisma.workspace.create({
      data: {
        name: 'Demo Workspace',
        slug: 'demo-workspace',
        plan: 'FREE',
        usageLimit: 10,
        ownerId: demoUser.id,
        dialectPreference: 'EGYPTIAN',
      },
    });

    console.log('✅ Workspace created:', workspace.name);

    // Add user to workspace
    await prisma.workspaceMember.create({
      data: {
        workspaceId: workspace.id,
        userId: demoUser.id,
        role: 'OWNER',
        joinedAt: new Date(),
      },
    });

    console.log('✅ User added to workspace');

    // Create sample generation
    const generation = await prisma.generation.create({
      data: {
        workspaceId: workspace.id,
        userId: demoUser.id,
        type: 'CAPTION',
        dialect: 'EGYPTIAN',
        tone: 'PROFESSIONAL',
        prompt: 'اكتب نص لتسويق منتج جديد على إنستغرام',
        result: [
          {
            variant: 1,
            content: 'منتجنا الجديد هنا!  اكتشف الجودة والابتكار في كل استخدام. اطلب الآن واحصل على خصم 20% #جودة #منتجات_جديدة',
            charCount: 95,
          },
          {
            variant: 2,
            content: 'الآن متاح! ✨ تجربة فريدة مع منتجك الجديد المفضل. جودة عالية وسعر مناسب. اشتري الآن! #مشتريات #منتج_جديد',
            charCount: 88,
          },
          {
            variant: 3,
            content: 'لا تفوتها!  منتج جديد يغير حياتك. عالية الجودة ومضمونة. اطلب اليوم وستشعر بالفرق! #استثمار_ذكي',
            charCount: 85,
          },
        ],
        tokensUsed: 0,
        model: 'claude-sonnet-4-20250514',
      },
    });

    console.log('✅ Sample generation created');

    console.log('\n Database seeded successfully!\n');
    console.log(' Demo Credentials:');
    console.log('   Email: demo@kateb.ai');
    console.log('   Password: Demo@123456\n');
  } catch (error) {
    console.error('❌ Error seeding database:', error);
    process.exit(1);
  } finally {
    await prisma.$disconnect();
  }
}

main();

