import { PrismaClient } from '@prisma/client';

const globalForPrisma = global as unknown as { prisma: PrismaClient };

// Ensure DATABASE_URL is available - Prisma v7 requires it
if (!process.env.DATABASE_URL) {
  // Set a default for build time - will be overridden at runtime
  process.env.DATABASE_URL = 'postgresql://user:password@localhost:5432/kateb';
}

export const db =
  globalForPrisma.prisma ||
  new PrismaClient({
    log:
      process.env.NODE_ENV === 'development'
        ? ['error', 'warn']
        : ['error'],
  });

if (process.env.NODE_ENV !== 'production') globalForPrisma.prisma = db;

export default db;

import { PrismaClient } from '@prisma/client';

const globalForPrisma = global as unknown as { prisma: PrismaClient };

export const db =
  globalForPrisma.prisma ||
  new PrismaClient({
    log: process.env.NODE_ENV === 'development'
      ? ['error', 'warn']
      : ['error'],
  });

if (process.env.NODE_ENV !== 'production') globalForPrisma.prisma = db;

export default db;

@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  :root {
    --background: 0 0% 100%;
    --foreground: 0 0% 3.6%;

    --card: 0 0% 100%;
    --card-foreground: 0 0% 3.6%;

    --popover: 0 0% 100%;
    --popover-foreground: 0 0% 3.6%;

    --muted: 0 0% 96.1%;
    --muted-foreground: 0 0% 45.1%;

    --accent: 217 91% 60%;
    --accent-foreground: 0 0% 100%;

    --destructive: 0 84.2% 60.2%;
    --destructive-foreground: 0 0% 100%;

    --border: 0 0% 89.8%;
    --input: 0 0% 89.8%;
    --ring: 217 91% 60%;

    --radius: 0.75rem;

    --primary: 217 91% 60%;
    --primary-foreground: 210 40% 98%;

    --secondary: 217 32% 17%;
    --secondary-foreground: 210 40% 98%;
  }

  .dark {
    --background: 0 0% 100%;
    --foreground: 0 0% 3.6%;
    --card: 0 0% 100%;
    --card-foreground: 0 0% 3.6%;
    --popover: 0 0% 100%;
    --popover-foreground: 0 0% 3.6%;
    --muted: 0 0% 96.1%;
    --muted-foreground: 0 0% 45.1%;
    --accent: 217 91% 60%;
    --accent-foreground: 0 0% 100%;
    --border: 0 0% 89.8%;
    --input: 0 0% 89.8%;
    --primary: 217 91% 60%;
    --primary-foreground: 210 40% 98%;
  }
}

html {
  @apply scroll-smooth;
  color-scheme: light;
}

* {
  @apply border-border;
  color-scheme: light;
}

body {
  @apply bg-background text-foreground;
  font-feature-settings: "rounding-mode" 0;
  background-color: #ffffff;
  color: #1a1a1a;
}

/* Arabic RTL support */
[dir="rtl"] {
  direction: rtl;
  text-align: right;
}

[dir="rtl"] [dir="ltr"] {
  direction: ltr;
  text-align: left;
}

/* Modern gradient backgrounds */
.gradient-primary {
  background: linear-gradient(135deg, #4f46e5 0%, #7c3aed 100%);
}

.gradient-accent {
  background: linear-gradient(135deg, #06b6d4 0%, #3b82f6 100%);
}

/* Custom scrollbar */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  @apply bg-secondary/10;
}

::-webkit-scrollbar-thumb {
  @apply bg-primary/50 rounded-full hover:bg-primary;
}

/* Smooth animations */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes slideInLeft {
  from {
    opacity: 0;
    transform: translateX(-20px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes float {
  0%, 100% {
    transform: translateY(0px);
  }
  50% {
    transform: translateY(-10px);
  }
}

.animate-fade-in-up {
  animation: fadeInUp 0.6s ease-out;
}

.animate-slide-in-left {
  animation: slideInLeft 0.6s ease-out;
}

.animate-float {
  animation: float 3s ease-in-out infinite;
}

/* Smooth gradient text */
.gradient-text {
  @apply bg-clip-text text-transparent;
  background-image: linear-gradient(135deg, #4f46e5 0%, #7c3aed 100%);
}

/* Modern shadows */
.shadow-modern {
  box-shadow: 0 10px 30px rgba(79, 70, 229, 0.15);
}

.shadow-modern-lg {
  box-shadow: 0 20px 50px rgba(79, 70, 229, 0.2);
}

/* Interactive hover effects */
.hover-lift {
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.hover-lift:hover {
  transform: translateY(-4px);
  box-shadow: 0 15px 40px rgba(0, 0, 0, 0.1);
}

/* Arabic letter hover effect */
.arabic-letter-hover {
  position: relative;
  overflow: hidden;
  min-height: 150px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.arabic-letter {
  position: absolute;
  font-size: 6rem;
  font-weight: 900;
  opacity: 0;
  pointer-events: none;
  transform: scale(0) rotate(-20deg);
  transition: all 0.5s cubic-bezier(0.34, 1.56, 0.64, 1);
  color: rgba(79, 70, 229, 0.15);
  z-index: 0;
  line-height: 1;
  letter-spacing: 0.1em;
}

.arabic-letter-hover:hover .arabic-letter {
  opacity: 1;
  transform: scale(1) rotate(0deg);
}

/* Modern card styles */
.card-modern {
  @apply bg-white rounded-2xl p-6 border border-gray-100 transition-all duration-300;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
}

.card-modern:hover {
  @apply border-primary/20;
  box-shadow: 0 12px 30px rgba(79, 70, 229, 0.1);
}

/* Modern spacing */
@layer components {
  .section-padding {
    @apply py-16 sm:py-20 md:py-24;
  }

  .container-modern {
    @apply max-w-7xl mx-auto px-4 sm:px-6 lg:px-8;
  }
}
